import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, useLocation, Navigate } from 'react-router-dom';
import Login from './pages/Login';
import Colaboradores from './pages/Colaboradores';
import Processamento from './pages/Processamento';
import Configuracoes from './pages/Configuracoes';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import { configuracaoEmpresa, colaboradores as mockColaboradores } from './data/mockData';
import { Colaborador, ConfiguracaoEmpresa } from './types';

interface User {
  email: string;
  name: string;
}

interface AppContextType {
  user: User | null;
  setUser: (user: User | null) => void;
  isAuthenticated: boolean;
  setIsAuthenticated: (value: boolean) => void;
  isConfigured: boolean;
  setIsConfigured: (value: boolean) => void;
  empresas: any[];
  setEmpresas: (value: any[]) => void;
  empresa: any;
  setEmpresa: (value: any) => void;
  empresaId: number | null;
  setEmpresaId: (value: number | null) => void;
  colaboradores: Colaborador[];
  setColaboradores: (value: Colaborador[]) => void;
}

export const AppContext = React.createContext<AppContextType>({
  user: null,
  setUser: () => {},
  isAuthenticated: false,
  setIsAuthenticated: () => {},
  isConfigured: false,
  setIsConfigured: () => {},
  empresas: [],
  setEmpresas: () => {},
  empresa: null,
  setEmpresa: () => {},
  empresaId: null,
  setEmpresaId: () => {},
  colaboradores: [],
  setColaboradores: () => {},
});

function App() {
  const [user, setUser] = useState<User | null>(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isConfigured, setIsConfigured] = useState(false);
  const [empresas, setEmpresas] = useState<any[]>([]);
  const [empresa, setEmpresa] = useState<any>(null);
  const [empresaId, setEmpresaId] = useState<number | null>(null);
  const [colaboradores, setColaboradores] = useState<Colaborador[]>([]);

  return (
    <AppContext.Provider value={{ user, setUser, isAuthenticated, setIsAuthenticated, isConfigured, setIsConfigured, empresas, setEmpresas, empresa, setEmpresa, empresaId, setEmpresaId, colaboradores, setColaboradores }}>
      <Router future={{ v7_startTransition: true, v7_relativeSplatPath: true }}>
        <Routes>
          <Route path="/login" element={<Login />} />
          <Route path="*" element={isAuthenticated ? <MainLayout /> : <Navigate to="/login" replace />} />
        </Routes>
      </Router>
    </AppContext.Provider>
  );
}

function MainLayout() {
  const location = useLocation();
  const [currentPage, setCurrentPage] = useState('processamento');
  const { isConfigured, empresa } = React.useContext(AppContext);

  useEffect(() => {
    const path = location.pathname.replace('/', '') || 'processamento';
    setCurrentPage(path);
  }, [location]);

  const hasEmpresa = empresa && empresa.nome && empresa.nif;

  return (
    <div className="flex min-h-screen bg-background-light dark:bg-background-dark">
      {hasEmpresa ? (
        <div className="w-64 shrink-0 fixed h-full z-20">
          <Sidebar currentPage={currentPage} setCurrentPage={setCurrentPage} />
        </div>
      ) : (
        <div className="w-64 shrink-0 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 p-6 hidden md:flex flex-col fixed h-full z-20">
          <div className="flex items-center gap-3 mb-10">
            <div className="bg-primary/10 p-2 rounded-lg text-primary">
              <span className="material-symbols-outlined">payments</span>
            </div>
            <h1 className="text-2xl font-black tracking-tight text-slate-800 dark:text-white">SALYA</h1>
          </div>
          <div className="text-slate-500 text-sm mt-4">
            <p>Por favor, configure a sua empresa antes de aceder ao sistema.</p>
          </div>
        </div>
      )}
      <div className={`flex-1 flex flex-col min-h-screen ${isConfigured ? 'ml-64 w-[calc(100%-16rem)]' : 'w-full'}`}>
        <Header />
        <main className="flex-1 p-0">
          {(!hasEmpresa && currentPage !== 'configuracoes') ? (
            <Navigate to="/configuracoes" replace />
          ) : (
            <Routes>
              {hasEmpresa && (
                <>
                  <Route path="/" element={<Navigate to="/processamento" replace />} />
                  <Route path="/dashboard" element={<Navigate to="/processamento" replace />} />
                  <Route path="/colaboradores" element={<Colaboradores />} />
                  <Route path="/processamento" element={<Processamento />} />
                </>
              )}
              <Route path="/configuracoes" element={<Configuracoes />} />
            </Routes>
          )}
        </main>
        <footer className="mt-auto p-8 border-t border-slate-200 dark:border-slate-800 text-center text-sm text-slate-500">
          © 2026 SALYA. Todos os direitos reservados.
        </footer>
      </div>
    </div>
  );
}

export default App;
